import mysql.connector

def import_data_to_mysql(file_path, table_name, db_config):
    try:
        # Connect to MySQL database
        connection = mysql.connector.connect(**db_config)
        cursor = connection.cursor()

        # Enable local_infile
        cursor.execute("SET GLOBAL local_infile = 1")

        # Construct LOAD DATA INFILE query
        query = "LOAD DATA INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\\n'".format(file_path, table_name)

        # Execute the query
        cursor.execute(query)
        connection.commit()

        print("Data imported successfully into table {}".format(table_name))

    except mysql.connector.Error as err:
        print("Error: {}".format(err))
    finally:
        if connection.is_connected():
            cursor.close()
            connection.close()

